 1	import React, { FC } from 'react';
 2	
 3	import { Card, CardBody, CardHeader, CardTitle, Grid, GridItem } from '@patternfly/react-core';
 4	import Area from '@utils/components/Area/Area';
 5	import Dashboard from '@utils/components/Dashboard/Dashboard';
 6	import { useIsAdmin } from '@utils/hooks/useIsAdmin';
 7	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
 8	import { getName, getNamespace } from '@utils/resources/shared';
 9	import { RouteKind } from '@utils/types';
10	
11	import { humanizeDecimalBytesPerSec } from '../../../../../../utils/utils/units';
12	
13	type RouteMetricsTabProps = {
14	  obj: RouteKind;
15	};
16	
17	const RouteMetricsTab: FC<RouteMetricsTabProps> = ({ obj: route }) => {
18	  const { t } = useNetworkingTranslation();
19	  const isAdmin = useIsAdmin();
20	
21	  if (!isAdmin) return null;
22	
23	  const namespaceRouteQuery = `{exported_namespace="${getNamespace(route)}",route="${getName(route)}"}[5m]`;
24	
25	  return (
26	    <Dashboard className="resource-metrics-dashboard">
27	      <Grid hasGutter>
28	        <GridItem lg={12} xl={6}>
29	          <Card className="resource-metrics-dashboard__card">
30	            <CardHeader>
31	              <CardTitle>{t('Traffic in')}</CardTitle>
32	            </CardHeader>
33	            <CardBody className="resource-metrics-dashboard__card-body">
34	              <Area
35	                humanize={humanizeDecimalBytesPerSec}
36	                query={`sum without (instance,exported_pod,exported_service,pod,server) (irate(haproxy_server_bytes_in_total${namespaceRouteQuery}))`}
37	              />
38	            </CardBody>
39	          </Card>
40	        </GridItem>
41	        <GridItem lg={12} xl={6}>
42	          <Card className="resource-metrics-dashboard__card">
43	            <CardHeader>
44	              <CardTitle>{t('Traffic out')}</CardTitle>
45	            </CardHeader>
46	            <CardBody className="resource-metrics-dashboard__card-body">
47	              <Area
48	                humanize={humanizeDecimalBytesPerSec}
49	                query={`sum without (instance,exported_pod,exported_service,pod,server) (irate(haproxy_server_bytes_out_total${namespaceRouteQuery}))`}
50	              />
51	            </CardBody>
52	          </Card>
53	        </GridItem>
54	        <GridItem lg={12} xl={6}>
55	          <Card className="resource-metrics-dashboard__card">
56	            <CardHeader>
57	              <CardTitle>{t('Connection rate')}</CardTitle>
58	            </CardHeader>
59	            <CardBody className="resource-metrics-dashboard__card-body">
60	              <Area
61	                query={`sum without (instance,exported_pod,exported_service,pod,server) (irate(haproxy_backend_connections_total${namespaceRouteQuery}))`}
62	              />
63	            </CardBody>
64	          </Card>
65	        </GridItem>
66	      </Grid>
67	    </Dashboard>
68	  );
69	};
70	
71	export default RouteMetricsTab;

